(function () {
  "use strict";

  const CONFIG = {
    containerSelector: "#funlink-board",
    tileSelector: "button.funlink-tile",
    highlightColor: "#ff3b3b",
    highlightWidth: 4,
    autoScanInterval: 1000,
    
    autoClick: true, 
    delayBeforeStartMin: 500, 
    delayBeforeStartMax: 1000, 
    delayBetweenClicksMin: 500, 
    delayBetweenClicksMax: 1000, 
  };

  let overlayRoot = null, panelEl = null, statusEl = null;
  
  let isAutoClicking = false; 
  let isRunning = false; 

  function randomDelay(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
  }

  function scanBoard() {
    const container = document.querySelector(CONFIG.containerSelector);
    if (!container) return null;

    const tiles = Array.from(container.querySelectorAll(CONFIG.tileSelector));
    
    let maxR = 0, maxC = 0;
    tiles.forEach(t => {
      maxR = Math.max(maxR, parseInt(t.dataset.row));
      maxC = Math.max(maxC, parseInt(t.dataset.col));
    });

    const rows = maxR + 3;
    const cols = maxC + 3;
    const grid = Array.from({ length: rows }, () => Array(cols).fill(null));

    tiles.forEach(btn => {
      if (btn.classList.contains("matched")) return;

      const r = parseInt(btn.dataset.row) + 1;
      const c = parseInt(btn.dataset.col) + 1;
      const img = btn.querySelector("img");
      const id = img ? img.src : null;

      if (id) {
        grid[r][c] = { el: btn, id, r, c, rect: btn.getBoundingClientRect() };
      }
    });

    return { grid, rows, cols };
  }

  const DIRS = [[0, 1], [0, -1], [1, 0], [-1, 0]];

  function canConnect(grid, a, b) {
    const queue = [];
    for (let d = 0; d < 4; d++) queue.push({ r: a.r, c: a.c, dir: d, turns: 0 });
    const visited = new Map();
    let qi = 0;
    while (qi < queue.length) {
      const cur = queue[qi++];
      const [dr, dc] = DIRS[cur.dir];
      const nr = cur.r + dr, nc = cur.c + dc;
      if (nr < 0 || nc < 0 || nr >= grid.length || nc >= grid[0].length) continue;
      
      const cell = grid[nr][nc];
      if (cell !== null) {
        if (nr === b.r && nc === b.c) return true;
        continue;
      }

      for (let nd = 0; nd < 4; nd++) {
        const newTurns = cur.turns + (nd === cur.dir ? 0 : 1);
        if (newTurns > 2) continue;
        const key = `${nr},${nc},${nd}`;
        if (!visited.has(key) || visited.get(key) > newTurns) {
          visited.set(key, newTurns);
          queue.push({ r: nr, c: nc, dir: nd, turns: newTurns });
        }
      }
    }
    return false;
  }

  function findAllHints(grid) {
    const byId = new Map();
    grid.forEach(row => row.forEach(cell => {
      if (cell) {
        if (!byId.has(cell.id)) byId.set(cell.id, []);
        byId.get(cell.id).push(cell);
      }
    }));
    const hints = [];
    for (const cells of byId.values()) {
      for (let i = 0; i < cells.length; i++) {
        for (let j = i + 1; j < cells.length; j++) {
          if (canConnect(grid, cells[i], cells[j])) hints.push({ a: cells[i], b: cells[j] });
        }
      }
    }
    return hints;
  }

  function ensureOverlay() {
    if (!overlayRoot) {
      overlayRoot = document.createElement("div");
      overlayRoot.style.cssText = "position:fixed; top:0; left:0; width:100%; height:100%; pointer-events:none; z-index:9999;";
      document.body.appendChild(overlayRoot);
    }
    overlayRoot.innerHTML = "";
    return overlayRoot;
  }

  function drawBox(rect) {
    const box = document.createElement("div");
    box.style.cssText = `
      position:fixed; left:${rect.left}px; top:${rect.top}px;
      width:${rect.width}px; height:${rect.height}px;
      border:${CONFIG.highlightWidth}px solid ${CONFIG.highlightColor};
      border-radius:4px; box-shadow:0 0 10px ${CONFIG.highlightColor};
      pointer-events:none;
    `;
    overlayRoot.appendChild(box);
  }

  async function executeAutoClick(hint) {
    isAutoClicking = true; 
    
    const startDelay = randomDelay(CONFIG.delayBeforeStartMin, CONFIG.delayBeforeStartMax);
    if(statusEl && isRunning) statusEl.textContent = `Menunggu ${(startDelay/1000).toFixed(1)}s...`;
    await new Promise(resolve => setTimeout(resolve, startDelay));

    if (!isRunning) { isAutoClicking = false; return; }

    if(statusEl) statusEl.textContent = `Klik Tile 1!`;
    hint.a.el.click();

    const clickDelay = randomDelay(CONFIG.delayBetweenClicksMin, CONFIG.delayBetweenClicksMax);
    if(statusEl && isRunning) statusEl.textContent = `Jeda ${(clickDelay/1000).toFixed(1)}s...`;
    await new Promise(resolve => setTimeout(resolve, clickDelay));

    if (!isRunning) { isAutoClicking = false; return; }

    if(statusEl) statusEl.textContent = `Klik Tile 2!`;
    hint.b.el.click();

    await new Promise(resolve => setTimeout(resolve, 500));
    
    isAutoClicking = false; 
    if (isRunning) tick(); 
  }

  let currentHints = [];
  let hintIdx = 0;

  function tick() {
    if (!isRunning) return; 
    if (isAutoClicking) return; 

    const board = scanBoard();
    if (!board) return;
    
    currentHints = findAllHints(board.grid);
    
    if (currentHints.length > 0) {
      const hint = currentHints[hintIdx % currentHints.length];
      const root = ensureOverlay();
      
      drawBox(hint.a.rect);
      drawBox(hint.b.rect);
      
      if (CONFIG.autoClick) {
        executeAutoClick(hint);
      } else {
        if(statusEl) statusEl.textContent = `Ada ${currentHints.length} pasang`;
      }
    } else {
      // MODIFIKASI DI SINI: Tidak ada perintah isRunning = false lagi.
      ensureOverlay().innerHTML = "";
      if(statusEl) statusEl.textContent = "Menunggu level / papan baru...";
    }
  }

  let playBtn, pauseBtn;

  function updateButtonStates() {
    if (isRunning) {
      playBtn.style.opacity = "0.5";
      playBtn.style.cursor = "not-allowed";
      pauseBtn.style.opacity = "1";
      pauseBtn.style.cursor = "pointer";
    } else {
      playBtn.style.opacity = "1";
      playBtn.style.cursor = "pointer";
      pauseBtn.style.opacity = "0.5";
      pauseBtn.style.cursor = "not-allowed";
    }
  }

  if (!panelEl) {
    panelEl = document.createElement("div");
    panelEl.style.cssText = "position:fixed; bottom:20px; right:20px; z-index:10000; background:rgba(0,0,0,0.85); color:#fff; padding:12px; border-radius:8px; font-family:sans-serif; width: 220px; box-shadow: 0 4px 6px rgba(0,0,0,0.3);";
    
    const titleEl = document.createElement("div");
    titleEl.innerHTML = "<strong>🤖 AniMatch Bot</strong>";
    titleEl.style.marginBottom = "8px";
    panelEl.appendChild(titleEl);
    
    statusEl = document.createElement("div");
    statusEl.style.cssText = "font-size:13px; margin-bottom:12px; color:#4ade80;";
    statusEl.textContent = "Siap dijalankan (Paused).";
    panelEl.appendChild(statusEl);

    const btnContainer = document.createElement("div");
    btnContainer.style.cssText = "display: flex; gap: 8px;";
    
    playBtn = document.createElement("button");
    playBtn.innerHTML = "▶ Play";
    playBtn.style.cssText = "flex: 1; background: #4ade80; color: #064e3b; border: none; padding: 6px; border-radius: 4px; font-weight: bold; cursor: pointer; transition: opacity 0.2s;";
    playBtn.onclick = () => {
      if (isRunning) return;
      isRunning = true;
      statusEl.textContent = "Menganalisis papan...";
      statusEl.style.color = "#4ade80";
      updateButtonStates();
      tick();
    };

    pauseBtn = document.createElement("button");
    pauseBtn.innerHTML = "⏸ Pause";
    pauseBtn.style.cssText = "flex: 1; background: #f87171; color: #7f1d1d; border: none; padding: 6px; border-radius: 4px; font-weight: bold; cursor: pointer; transition: opacity 0.2s;";
    pauseBtn.onclick = () => {
      if (!isRunning) return;
      isRunning = false;
      statusEl.textContent = "Dihentikan (Paused).";
      statusEl.style.color = "#f87171";
      ensureOverlay().innerHTML = ""; 
      updateButtonStates();
    };

    btnContainer.appendChild(playBtn);
    btnContainer.appendChild(pauseBtn);
    panelEl.appendChild(btnContainer);
    
    document.body.appendChild(panelEl);
    updateButtonStates();
  }

  setInterval(tick, CONFIG.autoScanInterval);
  
})();
